const input = $json.body ?? $json;
const message = typeof input.message === 'string' ? input.message.trim() : '';
const mode = input.mode === 'voice' ? 'voice' : 'text';
const sessionId = typeof input.sessionId === 'string' && input.sessionId.trim() ? input.sessionId.trim() : 'beets-aibot-session';
if (!message) {
  throw new Error('Missing message');
}
const lowered = message.toLowerCase();
const requestedSources = {
  email: /mail|email|e-mail|inbox|schranka/.test(lowered),
  asana: /asana|ukol|úkol|task|projekt/.test(lowered),
  hubspot: /hubspot|lead|deal|obchod/.test(lowered),
  ga4: /analytics|ga4|návštěv|navstev|traffic|konverz/.test(lowered),
  googleAds: /google ads|kampaň|kampan|ppc|cpc|roas/.test(lowered),
};
return [{ json: { message, mode, sessionId, requestedSources, autonomousMode: false } }];

const data = $json;
const systemPrompt = `Jsi osobní executive assistant pro Martina Kubáska a BEETS.CZ. Odpovídej česky, stručně a prakticky. Nikdy si nevymýšlej čísla ani fakta, která nejsou v datech. Když data chybí, řekni to jasně. Pokud navrhuješ akce, vrať i krátké action IDs. Použij jen systémy, které byly skutečně dostupné.`;
const sourceSummary = Object.entries(data.requestedSources)
  .filter(([, enabled]) => enabled)
  .map(([name]) => name)
  .join(', ') || 'none';
const externalContext = {
  email: $json.emailSummary ?? null,
  asana: $json.asanaSummary ?? null,
  hubspot: $json.hubspotSummary ?? null,
  ga4: $json.ga4Summary ?? null,
  googleAds: $json.googleAdsSummary ?? null,
};
return [{
  json: {
    ...data,
    anthropicPayload: {
      model: 'claude-3-7-sonnet-latest',
      max_tokens: 1200,
      system: systemPrompt,
      messages: [
        {
          role: 'user',
          content: [
            {
              type: 'text',
              text: `User request: ${data.message}\n\nRequested sources: ${sourceSummary}\n\nAvailable context JSON:\n${JSON.stringify(externalContext, null, 2)}\n\nReturn a concise answer for the user. If an action is appropriate, include short action IDs in a section called ACTIONS at the end.`
            }
          ]
        }
      ]
    }
  }
}];

const content = Array.isArray($json.content) ? $json.content : [];
const reply = content
  .filter((item) => item.type === 'text')
  .map((item) => item.text)
  .join('\n\n')
  .trim();
const actions = [];
const actionMatch = reply.match(/ACTIONS:\s*([\s\S]*)$/i);
if (actionMatch?.[1]) {
  actionMatch[1]
    .split(/\n|,/)
    .map((value) => value.trim().replace(/^[-*]\s*/, ''))
    .filter(Boolean)
    .forEach((value) => actions.push(value));
}
return [{ json: { reply: reply || 'Claude returned no answer.', actions, sources: [] } }];
